/**
 * Updated helper to generate dynamic images based on the product name.
 * It uses the 'species' and 'name' to pull a fresh image from Unsplash.
 */
const pDynamic = (
  id: number, name: string, brand: string, sku: string,
  price: number, category: string, species: string,
  rating = 4.5, reviews = 24, badge: string | null = null
): Product => {
  // Encodes the name to be URL-friendly for the search query
  const query = encodeURIComponent(`${species} ${name}`);
  return {
    id, name, brand, sku, price, originalPrice: null,
    image: `https://loremflickr.com/400/400/${species},pet/all?lock=${id}`, // Using Lorempickr with a 'lock' for consistency
    rating, reviews, badge, category, species, inStock: true,
  };
};

